// ─── 5 sample accounts from samples/ directory ───
// Each has exactly one demo transcript (→ v1) and one onboarding transcript (→ v2).
// form_data is optional — set to a JSON object to merge into v2 memo.
//
// Paths are relative to project root (samples/ is mounted at /app/samples in Docker).
// runDemo.js and runOnboarding.js both try inputs/ first, then project root fallback.

return [
  {
    json: {
      company: 'davids-hvac',
      account_id: 'davids-hvac',
      demo_path: 'samples/acc1/demo/transcipt01.txt',
      onboarding_path: 'samples/acc1/onboarding/transcript011.txt',
      form_data: null
    }
  },
  {
    json: {
      company: 'toms-pest-wildlife',
      account_id: 'toms-pest-wildlife',
      demo_path: 'samples/acc2/demo/transcript02.txt',
      onboarding_path: 'samples/acc2/onboarding/transcript022.txt',
      form_data: null
    }
  },
  {
    json: {
      company: 'blue-oasis-pools',
      account_id: 'blue-oasis-pools',
      demo_path: 'samples/acc3/demo/transcript03.txt',
