      form_data: null
    }
  }
];

const account = $('Process One').item.json;
const v1 = $('Run v1 (Demo)').item.json;
const v2 = $input.item.json;

return [{ json: {
  company: account.company,
  v1: v1.ok ? 'ok' : 'FAIL',
  v2: v2.ok ? 'ok' : 'FAIL',
  company_name: v2.files?.memo?.company_name || v1.files?.memo?.company_name || account.company,
  form_applied: !!v2.form_applied,
  agent_id: (v2.files?.agentDraftSpec || v1.files?.agentDraftSpec || {}).agent_id || null,
  llm_id: (v2.files?.agentDraftSpec || v1.files?.agentDraftSpec || {}).llm_id || null
}}];

const account = $('Process One').item.json;
const v1 = $input.item.json;

return [{ json: {
  company: account.company,
  v1: 'FAIL',
  v2: 'skipped',
  error: v1.error || 'Pipeline A failed — v2 requires v1 baseline',
  company_name: account.company,
  form_applied: false,
  agent_id: null,
  llm_id: null
}}];
